#include <bits/stdc++.h>
using namespace std;
struct Node{
    int num,cnt;
}f[30004];
int n,m1,m2,s[10004],sum;
bool np[30004];
int main(){
    scanf("%d%d%d",&n,&m1,&m2);
    for(int i=1;i<=n;i++)
        scanf("%d",&s[i]);
    np[1]=1;
    for(int i=2;i<=m1;i++)
        if(!np[i]){
            if(m1%i==0){
            	int tot=0,tmp=m1;
            	while(tmp%i==0)
                	tot++,tmp/=i;
            	f[++sum]={i,tot*m2};
			}
            for(int j=i+i;j<=m1;j+=i)
                np[j]=1;
        }
    int ans=-1;
    for(int i=1;i<=n;i++){
        int t=0;
        bool flag=true;
        for(int j=1;j<=sum;j++){
            if(s[i]%f[j].num>0){
                flag=false;
                break;
            }
            int tot=0,tmp=s[i];
            while(tmp%f[j].num==0)
                tot++,tmp/=f[j].num;
            t=max(t,f[j].cnt/tot+(f[j].cnt%tot>0));
        }
        //printf("%d\n",t);
        if(!flag)
            continue;
        if(ans==-1 || ans>t)
            ans=t;
    }
    printf("%d",ans);
    return 0;
}
